import anthropic
import json
from dataclasses import dataclass
from enum import Enum
from typing import Any

client = anthropic.Anthropic()

class ApprovalDecision(str, Enum):
    APPROVED = "approved"
    DENIED = "denied"
    MODIFIED = "modified"

@dataclass
class ApprovalRequest:
    tool_name: str
    inputs: dict[str, Any]
    rationale: str  # Why the agent wants to call this tool

@dataclass
class ApprovalResponse:
    decision: ApprovalDecision
    modified_inputs: dict[str, Any] | None = None
    reason: str | None = None

def cli_approval_gate(request: ApprovalRequest) -> ApprovalResponse:
    """
    Present the approval request to the human via CLI.
    In production: replace with a notification system (email, Slack, web UI).
    """
    print("\n=== APPROVAL REQUIRED ===")
    print(f"Tool: {request.tool_name}")
    print(f"Inputs: {json.dumps(request.inputs, indent=2)}")
    print(f"Agent rationale: {request.rationale}")
    print("Options: [a]pprove / [d]eny / [m]odify inputs")
    choice = input("Decision: ").strip().lower()

    if choice == "a":
        return ApprovalResponse(decision=ApprovalDecision.APPROVED)
    elif choice == "d":
        reason = input("Reason for denial: ").strip()
        return ApprovalResponse(decision=ApprovalDecision.DENIED, reason=reason)
    elif choice == "m":
        print("Enter modified inputs as JSON (leave blank to approve as-is):")
        raw = input().strip()
        try:
            modified = json.loads(raw) if raw else request.inputs
        except json.JSONDecodeError:
            print("Invalid JSON — approving original inputs.")
            modified = request.inputs
        return ApprovalResponse(
            decision=ApprovalDecision.MODIFIED,
            modified_inputs=modified,
        )
    else:
        print("Unrecognized input — denying by default.")
        return ApprovalResponse(
            decision=ApprovalDecision.DENIED,
            reason="Unrecognized reviewer response",
        )

def dispatch_with_approval_gate(
    tool_name: str,
    inputs: dict,
    rationale: str,
    tool_impl,
    gate=cli_approval_gate,
) -> str:
    request = ApprovalRequest(
        tool_name=tool_name,
        inputs=inputs,
        rationale=rationale,
    )
    response = gate(request)
    if response.decision == ApprovalDecision.DENIED:
        return f"Action denied by reviewer: {response.reason or 'no reason given'}"
    final_inputs = (
        response.modified_inputs
        if response.decision == ApprovalDecision.MODIFIED
        else inputs
    )
    return tool_impl(final_inputs)

# Tools that require approval before execution:
APPROVAL_REQUIRED_TOOLS = {"send_email", "delete_record", "deploy"}

TOOLS = [
    {
        "name": "draft_email",
        "description": "Draft an email (does not send it).",
        "input_schema": {
            "type": "object",
            "properties": {
                "to": {"type": "string"},
                "subject": {"type": "string"},
                "body": {"type": "string"},
            },
            "required": ["to", "subject", "body"],
        },
    },
    {
        "name": "send_email",
        "description": "Send an email. Requires human approval.",
        "input_schema": {
            "type": "object",
            "properties": {
                "to": {"type": "string"},
                "subject": {"type": "string"},
                "body": {"type": "string"},
            },
            "required": ["to", "subject", "body"],
        },
    },
]

def run_agent_with_gates(task: str, tool_impls: dict, gate=cli_approval_gate) -> str:
    """Agent loop that requires approval for destructive tools."""
    messages = [{"role": "user", "content": task}]
    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=TOOLS,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if hasattr(b, "text")), "")
        messages.append({"role": "assistant", "content": resp.content})
        results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            if block.name in APPROVAL_REQUIRED_TOOLS:
                # Gate pauses here until human responds
                output = dispatch_with_approval_gate(
                    tool_name=block.name,
                    inputs=block.input,
                    rationale=f"Agent requested this during: '{task}'",
                    tool_impl=tool_impls[block.name],
                    gate=gate,
                )
            else:
                output = tool_impls[block.name](block.input)
            results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": output,
            })
        messages.append({"role": "user", "content": results})

# Auto-approve gate for tests
auto_approve = lambda req: ApprovalResponse(decision=ApprovalDecision.APPROVED)

tool_impls = {
    "draft_email": lambda i: f"Draft saved: {i['subject']}",
    "send_email": lambda i: f"Email sent to {i['to']}",
}

result = run_agent_with_gates(
    "Draft and send a summary email to alice@example.com about our Q2 results.",
    tool_impls=tool_impls,
    gate=auto_approve,
)
print(result)

import uuid
import time
from typing import Callable

# Simulated persistent store (in production: database or Redis)
PENDING_APPROVALS: dict[str, dict] = {}
APPROVAL_RESPONSES: dict[str, ApprovalResponse] = {}

def request_approval_async(request: ApprovalRequest) -> str:
    """
    Persist an approval request and return a request_id.
    The caller polls or waits for APPROVAL_RESPONSES[request_id] to be set.
    """
    request_id = str(uuid.uuid4())
    PENDING_APPROVALS[request_id] = {
        "tool_name": request.tool_name,
        "inputs": request.inputs,
        "rationale": request.rationale,
        "submitted_at": time.time(),
    }
    # In production: send notification (email, Slack, push) with a link to
    # a web UI where the reviewer can approve/deny/modify.
    print(f"[APPROVAL REQUEST] id={request_id}: {request.tool_name}({request.inputs})")
    return request_id

def poll_for_approval(request_id: str, timeout: float = 30.0) -> ApprovalResponse:
    """
    Wait up to timeout seconds for a reviewer to respond.
    In production: use asyncio.Event or a database long-poll instead of sleep loop.
    """
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        if request_id in APPROVAL_RESPONSES:
            return APPROVAL_RESPONSES.pop(request_id)
        time.sleep(0.5)
    # Timeout: deny by default (fail-safe)
    return ApprovalResponse(
        decision=ApprovalDecision.DENIED,
        reason=f"Approval timed out after {timeout}s",
    )

def async_approval_gate(request: ApprovalRequest) -> ApprovalResponse:
    """Gate that submits async and polls."""
    request_id = request_approval_async(request)
    return poll_for_approval(request_id, timeout=30.0)

# Simulate a reviewer approving via the web UI:
def simulate_reviewer_approve(request_id: str):
    APPROVAL_RESPONSES[request_id] = ApprovalResponse(
        decision=ApprovalDecision.APPROVED
    )

@dataclass
class BatchApprovalRequest:
    """Group multiple tool calls into one reviewer decision."""
    requests: list[ApprovalRequest]
    task_summary: str  # High-level description of what the agent is trying to do

def batch_approval_gate(batch: BatchApprovalRequest) -> list[ApprovalResponse]:
    """
    Present all pending approvals at once.
    Reviewer can approve all, deny all, or decide per-request.
    """
    print(f"\n=== BATCH APPROVAL ({len(batch.requests)} actions) ===")
    print(f"Task: {batch.task_summary}")
    for i, req in enumerate(batch.requests, 1):
        print(f"  {i}. {req.tool_name}({json.dumps(req.inputs)})")
    choice = input("Approve [a]ll / [d]eny all / [s]elect: ").strip().lower()
    if choice == "a":
        return [ApprovalResponse(decision=ApprovalDecision.APPROVED)] * len(batch.requests)
    elif choice == "d":
        return [ApprovalResponse(decision=ApprovalDecision.DENIED, reason="Batch denied")] * len(batch.requests)
    else:
        responses = []
        for req in batch.requests:
            resp = cli_approval_gate(req)
            responses.append(resp)
        return responses
